package quota

import (
	"context"
	"fmt"
	"sync"

	"github.com/sirupsen/logrus"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
	"github.com/cilium/cilium/pkg/logging"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

var log = logging.DefaultLogger.WithField(logfields.LogSubsys, "policy-quota")

// PolicyQuotaController enforces per-namespace limits on the number of
// CiliumNetworkPolicy resources.
type PolicyQuotaController struct {
	log logrus.FieldLogger

	// namespacePolicyCounts tracks the number of policies per namespace
	namespacePolicyCounts map[string]int
	mu                    sync.RWMutex

	// maxPerNamespace is the maximum number of policies allowed per namespace
	// A value of 0 means unlimited
	maxPerNamespace int

	// ciliumNetworkPolicies provides access to CiliumNetworkPolicy resources
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy]
}

// NewPolicyQuotaController creates a new PolicyQuotaController.
// maxPerNamespace specifies the maximum number of CiliumNetworkPolicy resources
// allowed per namespace. A value of 0 means unlimited.
func NewPolicyQuotaController(
	maxPerNamespace int,
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy],
) *PolicyQuotaController {
	return &PolicyQuotaController{
		log:                   log,
		namespacePolicyCounts: make(map[string]int),
		maxPerNamespace:       maxPerNamespace,
		ciliumNetworkPolicies: ciliumNetworkPolicies,
	}
}

// CheckQuota checks if a new policy can be created in the given namespace.
// Returns an error if the quota would be exceeded.
func (p *PolicyQuotaController) CheckQuota(namespace string) error {
	if p.maxPerNamespace == 0 {
		// Unlimited quota
		return nil
	}

	p.mu.RLock()
	defer p.mu.RUnlock()

	count := p.namespacePolicyCounts[namespace]
	if count >= p.maxPerNamespace {
		return fmt.Errorf(
			"policy quota exceeded for namespace %q: %d/%d policies",
			namespace, count, p.maxPerNamespace)
	}
	return nil
}

// Run starts the controller loop watching for changes to CiliumNetworkPolicy resources.
// It updates the internal count of policies per namespace as they are created and deleted.
func (p *PolicyQuotaController) Run(ctx context.Context) error {
	p.log.Info("PolicyQuotaController starting")

	events := p.ciliumNetworkPolicies.Events(ctx)

	for {
		select {
		case <-ctx.Done():
			p.log.Info("PolicyQuotaController stopping")
			return ctx.Err()
		case event, ok := <-events:
			if !ok {
				p.log.Info("PolicyQuotaController event channel closed")
				return nil
			}

			p.handleEvent(event)
		}
	}
}

// handleEvent processes a resource event and updates the namespace policy counts.
func (p *PolicyQuotaController) handleEvent(event resource.Event[*cilium_v2.CiliumNetworkPolicy]) {
	defer event.Done(nil)

	namespace := event.Key.Namespace
	if namespace == "" {
		p.log.WithField("key", event.Key).Warn("Received event with empty namespace")
		return
	}

	p.mu.Lock()
	defer p.mu.Unlock()

	switch event.Kind {
	case resource.Upsert:
		p.namespacePolicyCounts[namespace]++
		p.log.WithFields(logrus.Fields{
			logfields.K8sNamespace: namespace,
			"count":                p.namespacePolicyCounts[namespace],
		}).Debug("Policy created/updated")

	case resource.Delete:
		if count, exists := p.namespacePolicyCounts[namespace]; exists && count > 0 {
			p.namespacePolicyCounts[namespace]--
		}
		p.log.WithFields(logrus.Fields{
			logfields.K8sNamespace: namespace,
			"count":                p.namespacePolicyCounts[namespace],
		}).Debug("Policy deleted")

	case resource.Sync:
		p.log.Debug("Policy resource synced with API server")
	}
}

// GetNamespacePolicyCount returns the current number of policies in a namespace.
func (p *PolicyQuotaController) GetNamespacePolicyCount(namespace string) int {
	p.mu.RLock()
	defer p.mu.RUnlock()
	return p.namespacePolicyCounts[namespace]
}

