package quota

import (
	"context"
	"errors"
	"testing"
	"time"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
)

// mockResource is a mock implementation of resource.Resource for testing
type mockResource struct {
	eventChan chan resource.Event[*cilium_v2.CiliumNetworkPolicy]
}

func newMockResource() *mockResource {
	return &mockResource{
		eventChan: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy], 100),
	}
}

func (m *mockResource) Events(ctx context.Context, opts ...resource.EventsOpt) <-chan resource.Event[*cilium_v2.CiliumNetworkPolicy] {
	return m.eventChan
}

func (m *mockResource) Observe(ctx context.Context, next func(resource.Event[*cilium_v2.CiliumNetworkPolicy])) error {
	return nil
}

func (m *mockResource) Store(ctx context.Context) (resource.Store[*cilium_v2.CiliumNetworkPolicy], error) {
	return nil, errors.New("not implemented")
}

func (m *mockResource) sendEvent(kind resource.EventKind, namespace, name string, obj *cilium_v2.CiliumNetworkPolicy) {
	done := make(chan struct{})
	m.eventChan <- resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind: kind,
		Key: resource.Key{
			Name:      name,
			Namespace: namespace,
		},
		Object: obj,
		Done: func(err error) {
			close(done)
		},
	}
	<-done
}

func TestNewPolicyQuotaController(t *testing.T) {
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(10, mockRes)

	if controller == nil {
		t.Fatal("NewPolicyQuotaController returned nil")
	}
	if controller.maxPerNamespace != 10 {
		t.Errorf("expected maxPerNamespace=10, got %d", controller.maxPerNamespace)
	}
}

func TestCheckQuotaUnlimited(t *testing.T) {
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(0, mockRes) // 0 means unlimited

	// Add many policies
	for i := 0; i < 100; i++ {
		err := controller.CheckQuota("default")
		if err != nil {
			t.Errorf("CheckQuota should not fail with unlimited quota, but got: %v", err)
		}
	}
}

func TestCheckQuotaExceeded(t *testing.T) {
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(5, mockRes)

	// Manually set the policy count to test CheckQuota
	controller.mu.Lock()
	controller.namespacePolicyCounts["default"] = 5
	controller.mu.Unlock()

	err := controller.CheckQuota("default")
	if err == nil {
		t.Errorf("CheckQuota should return error when quota is exceeded")
	}
	if err != nil && !contains(err.Error(), "quota exceeded") {
		t.Errorf("expected error message to contain 'quota exceeded', got: %v", err)
	}
}

func TestCheckQuotaWithinLimit(t *testing.T) {
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(5, mockRes)

	// Manually set the policy count to test CheckQuota
	controller.mu.Lock()
	controller.namespacePolicyCounts["default"] = 3
	controller.mu.Unlock()

	err := controller.CheckQuota("default")
	if err != nil {
		t.Errorf("CheckQuota should not return error when count is within limit, but got: %v", err)
	}
}

func TestHandleEventUpsert(t *testing.T) {
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(10, mockRes)

	policy := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy",
			Namespace: "default",
		},
	}

	event := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind: resource.Upsert,
		Key: resource.Key{
			Name:      "test-policy",
			Namespace: "default",
		},
		Object: policy,
		Done:   func(err error) {},
	}

	controller.handleEvent(event)

	count := controller.GetNamespacePolicyCount("default")
	if count != 1 {
		t.Errorf("expected count=1 after upsert, got %d", count)
	}
}

func TestHandleEventDelete(t *testing.T) {
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(10, mockRes)

	// Set initial count
	controller.mu.Lock()
	controller.namespacePolicyCounts["default"] = 2
	controller.mu.Unlock()

	event := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind: resource.Delete,
		Key: resource.Key{
			Name:      "test-policy",
			Namespace: "default",
		},
		Done: func(err error) {},
	}

	controller.handleEvent(event)

	count := controller.GetNamespacePolicyCount("default")
	if count != 1 {
		t.Errorf("expected count=1 after delete, got %d", count)
	}
}

func TestHandleEventSync(t *testing.T) {
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(10, mockRes)

	event := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind: resource.Sync,
		Done: func(err error) {},
	}

	// Should not panic or error
	controller.handleEvent(event)

	count := controller.GetNamespacePolicyCount("default")
	if count != 0 {
		t.Errorf("expected count=0 after sync event, got %d", count)
	}
}

func TestMultipleNamespaces(t *testing.T) {
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(5, mockRes)

	// Simulate policies in different namespaces
	namespaces := []string{"ns1", "ns2", "ns3"}
	for _, ns := range namespaces {
		for i := 0; i < 3; i++ {
			event := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
				Kind: resource.Upsert,
				Key: resource.Key{
					Name:      "policy-" + ns + "-" + string(rune(i)),
					Namespace: ns,
				},
				Done: func(err error) {},
			}
			controller.handleEvent(event)
		}
	}

	// Check counts for each namespace
	for _, ns := range namespaces {
		count := controller.GetNamespacePolicyCount(ns)
		if count != 3 {
			t.Errorf("expected count=3 for namespace %q, got %d", ns, count)
		}
	}
}

func TestRunContextCancellation(t *testing.T) {
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(10, mockRes)

	ctx, cancel := context.WithCancel(context.Background())
	cancel() // Cancel immediately

	err := controller.Run(ctx)
	if err == nil {
		t.Errorf("Run should return error when context is cancelled")
	}
	if err != context.Canceled {
		t.Errorf("expected context.Canceled error, got %v", err)
	}
}

func TestRunEventProcessing(t *testing.T) {
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(10, mockRes)

	ctx, cancel := context.WithTimeout(context.Background(), 100*time.Millisecond)
	defer cancel()

	// Send an event asynchronously
	go func() {
		time.Sleep(10 * time.Millisecond)
		mockRes.sendEvent(resource.Upsert, "default", "policy-1", nil)
	}()

	// Run the controller
	_ = controller.Run(ctx)

	// Check if the event was processed
	count := controller.GetNamespacePolicyCount("default")
	if count != 1 {
		t.Errorf("expected count=1 after processing upsert event, got %d", count)
	}
}

func TestGetNamespacePolicyCount(t *testing.T) {
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(10, mockRes)

	// Initially should be 0
	count := controller.GetNamespacePolicyCount("default")
	if count != 0 {
		t.Errorf("expected initial count=0, got %d", count)
	}

	// Set count manually
	controller.mu.Lock()
	controller.namespacePolicyCounts["default"] = 5
	controller.mu.Unlock()

	count = controller.GetNamespacePolicyCount("default")
	if count != 5 {
		t.Errorf("expected count=5 after manual set, got %d", count)
	}

	// Check different namespace
	count = controller.GetNamespacePolicyCount("other")
	if count != 0 {
		t.Errorf("expected count=0 for other namespace, got %d", count)
	}
}

func TestThreadSafety(t *testing.T) {
	mockRes := newMockResource()
	controller := NewPolicyQuotaController(1000, mockRes)

	// Simulate concurrent operations
	done := make(chan struct{})
	for i := 0; i < 10; i++ {
		go func(id int) {
			ns := "ns-" + string(rune(id%3))
			for j := 0; j < 100; j++ {
				event := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
					Kind: resource.Upsert,
					Key: resource.Key{
						Name:      "policy",
						Namespace: ns,
					},
					Done: func(err error) {},
				}
				controller.handleEvent(event)
			}
			done <- struct{}{}
		}(i)
	}

	// Wait for all goroutines
	for i := 0; i < 10; i++ {
		<-done
	}

	// Verify counts are consistent
	total := 0
	for ns := 0; ns < 3; ns++ {
		count := controller.GetNamespacePolicyCount("ns-" + string(rune(ns)))
		total += count
	}

	expectedTotal := 10 * 100 // 10 goroutines, 100 operations each
	if total != expectedTotal {
		t.Errorf("expected total count=%d, got %d", expectedTotal, total)
	}
}

func contains(s, substr string) bool {
	for i := 0; i <= len(s)-len(substr); i++ {
		if s[i:i+len(substr)] == substr {
			return true
		}
	}
	return false
}

